return $input.all().map(item => {
  try {
    // 1️⃣ The Fix: We grab the text for THIS specific item in the batch loop
    // Common Mistake: Using $input.first() here drops all items except the first one.
    const rawOutput = item.json.text;

    if (!rawOutput) {
      throw new Error("No LLM output received");
    }

    // 2️⃣ Clean markdown if Gemini accidentally formats it as a code block
    const cleaned = rawOutput.replace(/```json|```/g, "").trim();

    // 3️⃣ Parse JSON safely
    let parsed;
    try {
      parsed = JSON.parse(cleaned);
    } catch (err) {
      // Brutally honest tip: Log the start of the string so you can debug *why* it failed
      throw new Error(`Invalid JSON from LLM. Output started with: ${cleaned.substring(0, 50)}...`);
    }

    // 4️⃣ Ensure required array fields always exist
    const requiredArrays = [
      "preferred_locations", "key_skills", "primary_skills",
      "secondary_skills", "languages_known", "tags",
      "education", "experience", "projects"
    ];

    requiredArrays.forEach(field => {
      if (!Array.isArray(parsed[field])) {
        parsed[field] = [];
      }
    });

    // 5️⃣ Ensure all top-level scalar fields exist
    const requiredScalars = [
      "full_name", "email", "secondary_email", "phone_primary",
      "phone_secondary", "whatsapp_number", "date_of_birth", "gender",
      "marital_status", "current_address", "permanent_address", "city",
      "state", "country", "pincode", "linkedin_url", "portfolio_url",
      "github_url", "current_company", "current_designation",
      "employment_type", "job_type_preference", "work_mode_preference",
      "source", "status", "pipeline_stage", "declaration_status",
      "bgv_status", "notes", "current_ctc", "expected_ctc_min",
      "expected_ctc_max", "total_experience_years",
      "relevant_experience_years", "notice_period_days", "last_working_day"
    ];

    requiredScalars.forEach(field => {
      if (!(field in parsed)) {
        parsed[field] = null;
      }
    });

    // 6️⃣ Add metadata (very important for bulk processing)
    // Heads up: Langchain nodes in n8n sometimes strip original 'id' fields.
    // If this outputs "ID_MISSING", you'll need to pass the ID via workflow variables or a merge node.
    parsed._meta = {
      processed_at: new Date().toISOString(),
      source_file_id: item.json.id || "ID_MISSING",
      success: true
    };

    // Return the formatted object for THIS item to the pipeline
    return { json: parsed };

  } catch (error) {
    // ⚠️ CRITICAL FAILSAFE: If one resume fails, do NOT crash the batch.
    // We return an error object so the next node can filter it out or log it.
    return {
      json: {
        error: true,
        message: error.message,
        raw_output: item.json?.text || null,
        _meta: {
          processed_at: new Date().toISOString(),
          success: false
        }
      }
    };
  }
});

return items.map((item) => {
  const jsonString = JSON.stringify(item.json, null, 2);

  // Dynamically pull the exact filename from the Download node
  const originalItem = $items("Download file")[0]; 
  const originalName = originalItem && originalItem.json.name 
    ? originalItem.json.name.replace(/\.pdf$/i, '') 
    : `resume_${Date.now()}`;

  return {
    json: {},
    binary: {
      data: {
        data: Buffer.from(jsonString).toString('base64'),
        mimeType: 'application/json',
        fileName: `${originalName}.json` // Now matches the PDF perfectly!
      }
    }
  };
});

