// 1️⃣ Grab the data from the specific previous nodes by their names
const allPdfs = $items("Search files and folders"); 
const parsedJsons = $items("Search files and folders1");

// 2️⃣ Create a fast-lookup list of resumes we've already parsed
const finishedNames = new Set(
  parsedJsons.map(item => {
    return (item.json.name || "").replace(/\.json$/i, "").toLowerCase().trim();
  })
);

// 3️⃣ Filter the original PDF list. 
const remainingResumes = allPdfs.filter(pdf => {
  const pdfName = (pdf.json.name || "").replace(/\.pdf$/i, "").toLowerCase().trim();
  return !finishedNames.has(pdfName);
});

// 4️⃣ Deep clone the objects to strip n8n's internal Proxy wrappers
// This specifically prevents the "A 'json' property isn't an object" error
return remainingResumes.map(item => ({
  json: JSON.parse(JSON.stringify(item.json))
}));

